  `asset_cash_and_cash_equivalents` decimal(20,2) DEFAULT NULL COMMENT '资产-货币资金(万元)',
  `asset_accounts_receivable` decimal(20,2) DEFAULT NULL COMMENT '资产-应收账款(万元)',
  `asset_inventory` decimal(20,2) DEFAULT NULL COMMENT '资产-存货(万元)',
  `asset_trading_financial_assets` decimal(20,2) DEFAULT NULL COMMENT '资产-交易性金融资产（万元）',
  `asset_construction_in_progress` decimal(20,2) DEFAULT NULL COMMENT '资产-在建工程（万元）',
  `asset_total_assets` decimal(20,2) DEFAULT NULL COMMENT '资产-总资产(万元)',
  `asset_total_assets_yoy_growth` decimal(10,4) DEFAULT NULL COMMENT '资产-总资产同比(%)',
  `liability_accounts_payable` decimal(20,2) DEFAULT NULL COMMENT '负债-应付账款(万元)',
  `liability_advance_from_customers` decimal(20,2) DEFAULT NULL COMMENT '负债-预收账款(万元)',
  `liability_total_liabilities` decimal(20,2) DEFAULT NULL COMMENT '负债-总负债(万元)',
  `liability_total_liabilities_yoy_growth` decimal(10,4) DEFAULT NULL COMMENT '负债-总负债同比(%)',
  `liability_contract_liabilities` decimal(20,2) DEFAULT NULL COMMENT '负债-合同负债（万元）',
  `liability_short_term_loans` decimal(20,2) DEFAULT NULL COMMENT '负债-短期借款（万元）',
  `asset_liability_ratio` decimal(10,4) DEFAULT NULL COMMENT '资产负债率(%)',
  `equity_unappropriated_profit` decimal(20,2) DEFAULT NULL COMMENT '股东权益-未分配利润（万元）',
  `equity_total_equity` decimal(20,2) DEFAULT NULL COMMENT '股东权益合计(万元)',
  `report_period` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '报告期',
  `report_year` int DEFAULT NULL COMMENT '报告期-年份',
  PRIMARY KEY (`serial_number`),
  KEY `idx_balance_stock_period` (`stock_code`,`report_period`)
) ENGINE=InnoDB AUTO_INCREMENT=2474 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='资产负债表';
