--
-- Table structure for table `cash_flow_sheet`
--

DROP TABLE IF EXISTS `cash_flow_sheet`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `cash_flow_sheet` (
  `serial_number` int NOT NULL AUTO_INCREMENT COMMENT '序号',
  `stock_code` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '股票代码',
  `stock_abbr` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '股票简称',
  `net_cash_flow` decimal(20,2) DEFAULT NULL COMMENT '净现金流(元)',
  `net_cash_flow_yoy_growth` decimal(10,4) DEFAULT NULL COMMENT '净现金流-同比增长(%)',
  `operating_cf_net_amount` decimal(20,2) DEFAULT NULL COMMENT '经营性现金流-现金流量净额(万元)',
  `operating_cf_ratio_of_net_cf` decimal(10,4) DEFAULT NULL COMMENT '经营性现金流-净现金流占比(%)',
  `operating_cf_cash_from_sales` decimal(20,2) DEFAULT NULL COMMENT '经营性现金流-销售商品收到的现金（万元）',
  `investing_cf_net_amount` decimal(20,2) DEFAULT NULL COMMENT '投资性现金流-现金流量净额(万元)',
  `investing_cf_ratio_of_net_cf` decimal(10,4) DEFAULT NULL COMMENT '投资性现金流-净现金流占比(%)',
  `investing_cf_cash_for_investments` decimal(20,2) DEFAULT NULL COMMENT '投资性现金流-投资支付的现金（万元）',
  `investing_cf_cash_from_investment_recovery` decimal(20,2) DEFAULT NULL COMMENT '投资性现金流-收回投资收到的现金（万元）',
  `financing_cf_cash_from_borrowing` decimal(20,2) DEFAULT NULL COMMENT '融资性现金流-取得借款收到的现金（万元）',
  `financing_cf_cash_for_debt_repayment` decimal(20,2) DEFAULT NULL COMMENT '融资性现金流-偿还债务支付的现金（万元）',
  `financing_cf_net_amount` decimal(20,2) DEFAULT NULL COMMENT '融资性现金流-现金流量净额(万元)',
  `financing_cf_ratio_of_net_cf` decimal(10,4) DEFAULT NULL COMMENT '融资性现金流-净现金流占比(%)',
  `report_period` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '报告期',
  `report_year` int DEFAULT NULL COMMENT '报告期-年份',
  PRIMARY KEY (`serial_number`),
  KEY `idx_cashflow_stock_period` (`stock_code`,`report_period`)
) ENGINE=InnoDB AUTO_INCREMENT=2278 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='现金流量表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `cash_flow_sheet`
--

LOCK TABLES `cash_flow_sheet` WRITE;
/*!40000 ALTER TABLE `cash_flow_sheet` DISABLE KEYS */;
