--
-- Table structure for table `core_performance_indicators_sheet`
--

DROP TABLE IF EXISTS `core_performance_indicators_sheet`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `core_performance_indicators_sheet` (
  `serial_number` int NOT NULL AUTO_INCREMENT COMMENT '序号',
  `stock_code` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '股票代码',
  `stock_abbr` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '股票简称',
  `eps` decimal(10,4) DEFAULT NULL COMMENT '每股收益(元)',
  `total_operating_revenue` decimal(20,2) DEFAULT NULL COMMENT '营业总收入(万元)',
  `operating_revenue_yoy_growth` decimal(10,4) DEFAULT NULL COMMENT '营业总收入-同比增长(%)',
  `operating_revenue_qoq_growth` decimal(10,4) DEFAULT NULL COMMENT '营业总收入-季度环比增长(%)',
  `net_profit_10k_yuan` decimal(20,2) DEFAULT NULL COMMENT '净利润(万元)',
  `net_profit_yoy_growth` decimal(10,4) DEFAULT NULL COMMENT '净利润-同比增长(%)',
  `net_profit_qoq_growth` decimal(10,4) DEFAULT NULL COMMENT '净利润-季度环比增长(%)',
  `net_asset_per_share` decimal(10,4) DEFAULT NULL COMMENT '每股净资产(元)',
  `roe` decimal(10,4) DEFAULT NULL COMMENT '净资产收益率(%)',
  `operating_cf_per_share` decimal(10,4) DEFAULT NULL COMMENT '每股经营现金流量(元)',
  `net_profit_excl_non_recurring` decimal(20,2) DEFAULT NULL COMMENT '扣非净利润（万元）',
  `net_profit_excl_non_recurring_yoy` decimal(10,4) DEFAULT NULL COMMENT '扣非净利润同比增长（%）',
  `gross_profit_margin` decimal(10,4) DEFAULT NULL COMMENT '销售毛利率(%)',
  `net_profit_margin` decimal(10,4) DEFAULT NULL COMMENT '销售净利率（%）',
  `roe_weighted_excl_non_recurring` decimal(10,4) DEFAULT NULL COMMENT '加权平均净资产收益率（扣非）（%）',
  `report_period` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '报告期',
  `report_year` int DEFAULT NULL COMMENT '报告期-年份',
  PRIMARY KEY (`serial_number`),
  KEY `idx_core_stock_period` (`stock_code`,`report_period`)
) ENGINE=InnoDB AUTO_INCREMENT=2491 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='核心业绩指标表';
/*!40101 SET character_set_client = @saved_cs_client */;

