--
-- Table structure for table `income_sheet`
--

DROP TABLE IF EXISTS `income_sheet`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `income_sheet` (
  `serial_number` int NOT NULL AUTO_INCREMENT COMMENT '序号',
  `stock_code` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '股票代码',
  `stock_abbr` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '股票简称',
  `net_profit` decimal(20,2) DEFAULT NULL COMMENT '净利润(万元)',
  `net_profit_yoy_growth` decimal(10,4) DEFAULT NULL COMMENT '净利润同比(%)',
  `other_income` decimal(20,2) DEFAULT NULL COMMENT '其他收益（万元）',
  `total_operating_revenue` decimal(20,2) DEFAULT NULL COMMENT '营业总收入(万元)',
  `operating_revenue_yoy_growth` decimal(10,4) DEFAULT NULL COMMENT '营业总收入同比(%)',
  `operating_expense_cost_of_sales` decimal(20,2) DEFAULT NULL COMMENT '营业总支出-营业支出(万元)',
  `operating_expense_selling_expenses` decimal(20,2) DEFAULT NULL COMMENT '营业总支出-销售费用(万元)',
  `operating_expense_administrative_expenses` decimal(20,2) DEFAULT NULL COMMENT '营业总支出-管理费用(万元)',
  `operating_expense_financial_expenses` decimal(20,2) DEFAULT NULL COMMENT '营业总支出-财务费用(万元)',
  `operating_expense_rnd_expenses` decimal(20,2) DEFAULT NULL COMMENT '营业总支出-研发费用（万元）',
  `operating_expense_taxes_and_surcharges` decimal(20,2) DEFAULT NULL COMMENT '营业总支出-税金及附加（万元）',
  `total_operating_expenses` decimal(20,2) DEFAULT NULL COMMENT '营业总支出(万元)',
  `operating_profit` decimal(20,2) DEFAULT NULL COMMENT '营业利润(万元)',
  `total_profit` decimal(20,2) DEFAULT NULL COMMENT '利润总额(万元)',
  `asset_impairment_loss` decimal(20,2) DEFAULT NULL COMMENT '资产减值损失（万元）',
  `credit_impairment_loss` decimal(20,2) DEFAULT NULL COMMENT '信用减值损失（万元）',
  `report_period` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '报告期',
  `report_year` int DEFAULT NULL COMMENT '报告期-年份',
  PRIMARY KEY (`serial_number`),
  KEY `idx_income_stock_period` (`stock_code`,`report_period`)
) ENGINE=InnoDB AUTO_INCREMENT=2507 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='利润表';
/*!40101 SET character_set_client = @saved_cs_client */;

